<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">$</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chmod</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> g+s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /srv/project</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">    # 设置 SGID</span></span>
